'use client'; // Production deployment trigger v1.0.1

import React, { useState, useEffect } from 'react';
import ClassCard from '@/components/registration/ClassCard';
import FullscreenModal from '@/components/common/FullscreenModal';
import ClassDetail from '@/components/registration/ClassDetail';
import IdentityForm from '@/components/registration/IdentityForm';
import ClassEditor from '@/components/admin/ClassEditor';
import FooterMenu from '@/components/common/FooterMenu';
import MembershipGuide from '@/components/dashboard/MembershipGuide';
import RegistrationStatus from '@/components/dashboard/RegistrationStatus';
import RegistrationAdmin from '@/components/admin/RegistrationAdmin';
import { getClasses, addClass, updateClass, deleteClass, getRegistrations, TangoClass, Registration } from '@/lib/db';
import styles from './page.module.css';

export default function Home() {
  const [classes, setClasses] = useState<TangoClass[]>([]);
  const [registrations, setRegistrations] = useState<Registration[]>([]);
  const [selectedClassId, setSelectedClassId] = useState<string | null>(null);
  const [modalView, setModalView] = useState<'detail' | 'edit'>('detail');
  const [isLoading, setIsLoading] = useState(true);
  const [currentUser, setCurrentUser] = useState<{ nickname: string, phone: string, role?: 'leader' | 'follower' } | null>(null);
  const [appliedClassIds, setAppliedClassIds] = useState<Set<string>>(new Set());

  // Navigation state
  const [activeTab, setActiveTab] = useState<string>('home');
  const [isAdminLogged, setIsAdminLogged] = useState(false);
  const [adminInputPw, setAdminInputPw] = useState('');
  const [adminSubTab, setAdminSubTab] = useState<'classes' | 'registrations'>('registrations');

  // Identity Interceptor
  const [showIdentityForm, setShowIdentityForm] = useState(false);
  const [pendingAction, setPendingAction] = useState<(() => void) | null>(null);

  const requireIdentity = (action: () => void) => {
    const savedUser = localStorage.getItem('ft_user');
    if (savedUser) {
      action();
    } else {
      setPendingAction(() => action);
      setShowIdentityForm(true);
    }
  };

  const handleIdentityComplete = () => {
    setShowIdentityForm(false);
    if (pendingAction) {
      pendingAction();
      setPendingAction(null);
    }
  };

  useEffect(() => {
    fetchClasses();
    const loadUser = () => {
      const savedUser = localStorage.getItem('ft_user');
      if (savedUser) setCurrentUser(JSON.parse(savedUser));

      const savedClasses = localStorage.getItem('my_tango_classes');
      if (savedClasses) setAppliedClassIds(new Set(JSON.parse(savedClasses)));
    };
    loadUser();

    window.addEventListener('ft_user_updated', loadUser);
    window.addEventListener('ft_classes_updated', fetchClasses);
    window.addEventListener('ft_registrations_updated', fetchClasses);
    return () => {
      window.removeEventListener('ft_user_updated', loadUser);
      window.removeEventListener('ft_classes_updated', fetchClasses);
      window.removeEventListener('ft_registrations_updated', fetchClasses);
    };
  }, []);

  const fetchClasses = async () => {
    setIsLoading(true);
    try {
      const [classData, regData] = await Promise.all([getClasses(), getRegistrations()]);
      setClasses(classData);
      setRegistrations(regData);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleCardClick = (id: string) => {
    setModalView('detail');
    setSelectedClassId(id);
  };

  const handleRegisterClick = (id: string) => {
    requireIdentity(() => {
      const saved = localStorage.getItem('my_tango_classes');
      const setIds = saved ? new Set(JSON.parse(saved) as string[]) : new Set<string>();
      setIds.add(id);
      localStorage.setItem('my_tango_classes', JSON.stringify(Array.from(setIds)));
      setAppliedClassIds(new Set(setIds));
      window.dispatchEvent(new Event('ft_user_updated'));
      alert('?섏뾽???λ컮援щ땲???닿꼈?듬땲?? ?섎떒 [?댁떊泥?쁽?? 硫붾돱?먯꽌 ?쒓볼踰덉뿉 理쒖쥌 ?좎껌??吏꾪뻾?댁＜?몄슂.');
      handleCloseModal();
    });
  };

  const handleEdit = (_id: string) => {
    setModalView('edit');
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('?뺣쭚濡????섏뾽????젣?섏떆寃좎뒿?덇퉴?')) {
      try {
        await deleteClass(id);
        alert('??젣?섏뿀?듬땲??');
        handleCloseModal();
        fetchClasses();
      } catch (error: unknown) {
        console.error("Delete Error: ", error);
        const errorMessage = error instanceof Error ? error.message : String(error);
        alert('??젣 ?ㅽ뙣: ' + errorMessage);
      }
    }
  };

  const handleSave = async (data: Omit<TangoClass, 'id'> | Partial<TangoClass>) => {
    try {
      if (modalView === 'edit' && selectedClassId) {
        await updateClass(selectedClassId, data);
        alert('?섏젙?섏뿀?듬땲??');
        setModalView('detail');
      } else {
        await addClass(data as Omit<TangoClass, 'id'>);
        alert('?깅줉?섏뿀?듬땲??');
        setActiveTab('home'); // Go back home after adding
      }
      fetchClasses();
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      alert('????ㅽ뙣: ' + errorMessage);
    }
  };

  const handleCloseModal = () => {
    setSelectedClassId(null);
    setModalView('detail');
  };

  const groupedClasses = classes.reduce((acc, cls) => {
    const dayName = cls.time.match(/([?뷀솕?섎ぉ湲덊넗???붿씪)/)?.[1] || '湲고?';
    if (!acc[dayName]) acc[dayName] = [];
    acc[dayName].push(cls);
    return acc;
  }, {} as Record<string, TangoClass[]>);

  const selectedClass = classes.find(c => c.id === selectedClassId);

  return (
    <div className={styles.container}>

      {activeTab === 'home' && (
        <>
          <header className={styles.header}>
            <div className={styles.titleCard}>
              <div className={styles.titleLine1}>?꾨━?ㅽ??쇳꺊怨?/div>
              <div className={styles.titleLine2}>
                <span className={styles.highlight}>4??/span> ?섏뾽?좎껌
              </div>
            </div>

            <div 
              className={styles.profileArea}
              onClick={() => requireIdentity(() => {})}
            >
              {currentUser ? (
                <>
                  <div className={styles.profileText}>
                    <span className={styles.nickname}>{currentUser.nickname}</span>
                    <span 
                      className={styles.logoutBtn}
                      onClick={(e) => {
                        e.stopPropagation();
                        if (window.confirm('濡쒓렇?꾩썐 ?섏떆寃좎뒿?덇퉴?')) {
                          localStorage.removeItem('ft_user');
                          setCurrentUser(null);
                          window.dispatchEvent(new Event('ft_user_updated'));
                        }
                      }}
                    >
                      濡쒓렇?꾩썐
                    </span>
                  </div>
                  <div className={`${styles.profilePhoto} ${currentUser.role === 'leader' ? styles.male : styles.female}`} />
                </>
              ) : (
                <>
                  <div className={styles.profileText}>
                    <span className={styles.loginRequired}>濡쒓렇?명븘??/span>
                  </div>
                  <div className={styles.profilePhotoPlaceholder} />
                </>
              )}
            </div>
          </header>

          <main className={styles.mainContent}>
            {isLoading ? (
              <div style={{ textAlign: 'center', padding: '3rem', color: '#8b95a1' }}>濡쒕뵫 以?..</div>
            ) : classes.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '3rem', color: '#8b95a1' }}>?깅줉???섏뾽???놁뒿?덈떎.</div>
            ) : (
              ['?붿슂??, '?붿슂??, '?섏슂??, '紐⑹슂??, '湲덉슂??, '?좎슂??, '?쇱슂??, '湲고?']
                .filter(day => groupedClasses[day] && groupedClasses[day].length > 0)
                .map(day => (
                  <section key={day} className={styles.daySection}>
                    <h3 className={styles.dayTitle}>{day}</h3>
                    <div className={styles.cardList}>
                      {groupedClasses[day].map((cls) => {
                        // Calculate counts in real-time from registrations array
                        const leaderCount = registrations.filter(r => 
                          r.classIds.includes(cls.id) && (r.role || '').replace(/"/g, '') === 'leader'
                        ).length;
                        const followerCount = registrations.filter(r => 
                          r.classIds.includes(cls.id) && (r.role || '').replace(/"/g, '') === 'follower'
                        ).length;

                        return (
                          <ClassCard 
                            key={cls.id}
                            id={cls.id}
                            level={cls.level}
                            title={cls.title}
                            time={cls.time}
                            teacher={`${cls.teacher1}${cls.teacher2 ? ` & ${cls.teacher2}` : ''}`}
                            imageUrl={cls.imageUrl}
                            price={cls.price ? `${cls.price.toLocaleString()}?? : '0??}
                            leaderCount={leaderCount}
                            followerCount={followerCount}
                            maxCount={cls.maxCount || 20}
                            isApplied={appliedClassIds.has(cls.id)}
                            onClick={handleCardClick}
                          />
                        );
                      })}
                    </div>
                  </section>
                ))
            )}
          </main>
        </>
      )}

      {activeTab === 'membership' && (
        <main className={styles.mainContent} style={{ paddingTop: '2rem' }}>
          <MembershipGuide />
        </main>
      )}

      {activeTab === 'status' && (
        <main className={styles.mainContent} style={{ paddingTop: '0', paddingLeft: 0, paddingRight: 0 }}>
          <RegistrationStatus 
            classes={classes} 
            onClose={() => setActiveTab('home')} 
            requireIdentity={requireIdentity}
          />
        </main>
      )}

      {(activeTab === 'admin' || activeTab === 'add') && (
        <main className={styles.mainContent} style={{ paddingTop: '2rem' }}>
          {!isAdminLogged ? (
             <div style={{ textAlign: 'center', marginTop: '4rem' }}>
               <h2 style={{ marginBottom: '2rem', color: '#191f28' }}>愿由ъ옄 ?꾩슜</h2>
               <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '0.5rem' }}>
                 <input 
                   type="password" 
                   placeholder="鍮꾨?踰덊샇 4?먮━ ?낅젰"
                   value={adminInputPw}
                   onChange={(e) => setAdminInputPw(e.target.value)}
                   style={{ padding: '1rem', borderRadius: '12px', border: '1px solid #ddd', width: '200px', fontSize: '1rem' }}
                 />
                 <button 
                   onClick={() => {
                     if (adminInputPw === '9999') setIsAdminLogged(true);
                     else alert('鍮꾨?踰덊샇媛 ?쇱튂?섏? ?딆뒿?덈떎.');
                   }}
                   style={{ padding: '1rem 1.5rem', background: '#3182f6', color: '#fff', borderRadius: '12px', border: 'none', fontWeight: 700, fontSize: '1rem', cursor: 'pointer' }}
                 >
                   ?묒냽
                 </button>
               </div>
             </div>
          ) : (
              <div>
                <h2 style={{ marginBottom: '2rem', color: '#191f28', textAlign: 'center' }}>
                  {activeTab === 'add' ? '???섏뾽 ?깅줉' : '愿由ъ옄 ??쒕낫??}
                </h2>
                {activeTab === 'add' ? (
                  <ClassEditor onSave={handleSave} />
                ) : (
                  <div>
                    <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '2rem', justifyContent: 'center' }}>
                      <button 
                        onClick={() => setAdminSubTab('registrations')}
                        style={{ 
                          padding: '0.6rem 1.2rem', 
                          borderRadius: '100px', 
                          border: 'none',
                          background: adminSubTab === 'registrations' ? '#3182f6' : '#f2f4f6',
                          color: adminSubTab === 'registrations' ? '#fff' : '#4e5968',
                          fontWeight: 700,
                          fontSize: '0.9rem',
                          cursor: 'pointer'
                        }}
                      >
                        ?좎껌?꾪솴
                      </button>
                      <button 
                        onClick={() => setAdminSubTab('classes')}
                        style={{ 
                          padding: '0.6rem 1.2rem', 
                          borderRadius: '100px', 
                          border: 'none',
                          background: adminSubTab === 'classes' ? '#3182f6' : '#f2f4f6',
                          color: adminSubTab === 'classes' ? '#fff' : '#4e5968',
                          fontWeight: 700,
                          fontSize: '0.9rem',
                          cursor: 'pointer'
                        }}
                      >
                        ?대옒?ㅺ?由?n                      </button>
                    </div>

                    {adminSubTab === 'registrations' ? (
                      <RegistrationAdmin />
                    ) : (
                      <div style={{ padding: '4rem 2rem', background: '#f2f4f6', borderRadius: '16px', textAlign: 'center' }}>
                        <p style={{ color: '#8b95a1', marginBottom: '1rem' }}>?대옒??愿由?紐⑤뱶</p>
                        <p style={{ color: '#4e5968', fontSize: '0.85rem' }}>???붾㈃?먯꽌 ?대옒??移대뱶瑜??대┃?섎㈃<br/>?섏젙 諛???젣媛 媛?ν빀?덈떎.</p>
                      </div>
                    )}
                  </div>
                )}
              </div>
          )}
        </main>
      )}

      {/* ?섏뾽 ?곸꽭 / ?섏젙 ?꾩껜 ?붾㈃ ?앹뾽 (?ㅼ쭅 ????쓽 紐⑸줉?먯꽌 ?대┃?덉쓣 ?뚮쭔) */}
      <FullscreenModal
        isOpen={!!selectedClassId}
        onClose={handleCloseModal}
        title={modalView === 'detail' ? '?대옒???곸꽭' : '?섏뾽 ?뺣낫 ?섏젙'}
      >
        {selectedClass && (
          modalView === 'detail' ? (
            <ClassDetail 
              {...selectedClass}
              curriculum={selectedClass.curriculum}
              price={selectedClass.price}
              imageUrl={selectedClass.imageUrl}
              teacherProfile={selectedClass.teacherProfile}
              videoUrl={selectedClass.videoUrl}
              registrations={registrations.filter(r => r.classIds.includes(selectedClass.id))}
              onRegister={handleRegisterClick}
              onEdit={isAdminLogged ? handleEdit : undefined}
              onDelete={isAdminLogged ? handleDelete : undefined}
            />
          ) : (
            <ClassEditor 
              initialData={selectedClass} 
              onSave={handleSave} 
            />
          )
        )}
      </FullscreenModal>

      {/* Identity Bottom Sheet Popup */}
      <FullscreenModal
        isOpen={showIdentityForm}
        onClose={() => setShowIdentityForm(false)}
        title="?뺣낫 ?낅젰"
        isBottomSheet={true}
      >
        <IdentityForm 
          onClose={() => setShowIdentityForm(false)} 
          onComplete={handleIdentityComplete} 
        />
      </FullscreenModal>

      <FooterMenu onAction={(id) => setActiveTab(id)} />
    </div>
  );
}

'use client';

import React, { useState, useRef } from 'react';
import styles from './ClassEditor.module.css';
import { storage } from '@/lib/firebase';
import { ref, uploadBytesResumable, getDownloadURL } from 'firebase/storage';
import { TangoClass } from '@/lib/db';

interface ClassEditorProps {
  initialData?: Partial<TangoClass> | any; // Keep any for now for flex but prefer Partial<TangoClass>
  onSave: (data: Omit<TangoClass, 'id'> | Partial<TangoClass>) => void;
}

export default function ClassEditor({ initialData, onSave }: ClassEditorProps) {
  const [formData, setFormData] = useState({
    teacher1: initialData?.teacher1 || '',
    teacher2: initialData?.teacher2 || '',
    title: initialData?.title || '',
    type: initialData?.type || '泥댁씤吏?섏뾽',
    level: initialData?.level || 'Basic',
    description: initialData?.description || '',
    imageUrl: initialData?.imageUrl || '',
    price: initialData?.price || '',
    time: initialData?.time || '',
    videoUrl: initialData?.videoUrl || '',
    teacherProfile: initialData?.teacherProfile || '',
    leaderCount: initialData?.leaderCount || 0,
    followerCount: initialData?.followerCount || 0,
    maxCount: initialData?.maxCount || 15,
  });

  const [dates, setDates] = useState<string[]>(
    initialData?.dates?.length > 0 ? initialData.dates : ['', '', '', '']
  );
  let extractedStart = '20:00';
  let extractedEnd = '21:30';
  if (initialData?.timeStr) {
    const parts = initialData.timeStr.split('-');
    if (parts[0]) extractedStart = parts[0].trim().padStart(5, '0');
    if (parts[1]) extractedEnd = parts[1].trim().padStart(5, '0');
  } else if (initialData?.time) {
    const match = initialData.time.match(/(\d{1,2}:\d{2})\s*(?:-|~)\s*(\d{1,2}:\d{2})/);
    if (match) {
      extractedStart = match[1].padStart(5, '0');
      extractedEnd = match[2].padStart(5, '0');
    }
  }

  const [startTime, setStartTime] = useState(extractedStart);
  const [endTime, setEndTime] = useState(extractedEnd);

  const [hasCurriculum, setHasCurriculum] = useState(!!initialData?.curriculum);
  const [curriculumWeeks, setCurriculumWeeks] = useState<string[]>(
    initialData?.curriculum 
      ? initialData.curriculum.split('\n').map((s: string) => s.replace(/^\d+二쇱감:\s*/, '')) 
      : ['', '', '', '']
  );

  const [isImageUploading, setIsImageUploading] = useState(false);
  const [isVideoUploading, setIsVideoUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handlePriceChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Strip everything except numbers
    const rawValue = e.target.value.replace(/[^0-9]/g, '');
    if (!rawValue) {
      setFormData(prev => ({ ...prev, price: '' }));
      return;
    }
    // Format with commas and append '??
    const formatted = parseInt(rawValue, 10).toLocaleString('ko-KR') + '??;
    setFormData(prev => ({ ...prev, price: formatted }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImageUploading(true);
    const reader = new FileReader();
    reader.onloadend = () => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 800;
        let scale = 1;
        if (img.width > MAX_WIDTH) {
          scale = MAX_WIDTH / img.width;
        }
        canvas.width = img.width * scale;
        canvas.height = img.height * scale;

        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
          setFormData(prev => ({ ...prev, imageUrl: dataUrl }));
          setIsImageUploading(false);
        } else {
          alert("?대?吏 而⑦뀓?ㅽ듃瑜??앹꽦?섏? 紐삵뻽?듬땲??");
          setIsImageUploading(false);
        }
      };
      img.onerror = () => {
        alert("?대?吏 泥섎━???ㅽ뙣?덉뒿?덈떎.");
        setIsImageUploading(false);
      };
      img.src = reader.result as string;
    };
    reader.onerror = () => {
      alert("?대?吏 濡쒕뱶???ㅽ뙣?덉뒿?덈떎.");
      setIsImageUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 50 * 1024 * 1024) {
      alert("?숈쁺???뚯씪???덈Т ?쎈땲?? (理쒕? 50MB)");
      return;
    }

    setIsVideoUploading(true);
    setUploadProgress(0);

    const storageRef = ref(storage, `videos/${Date.now()}_${file.name}`);
    const uploadTask = uploadBytesResumable(storageRef, file);

    const timeoutId = setTimeout(() => {
      if (uploadProgress === 0 && isVideoUploading) {
        alert("?낅줈?쒓? ?쒖옉?섏? ?딆뒿?덈떎 (0%).\n\n?뺤씤 ?꾩슂:\n1. Firebase Storage 洹쒖튃?먯꽌 'allow read, write: if true' ?ㅼ젙???섏뼱?덈굹??\n2. Vercel ?섍꼍蹂??Storage Bucket)媛 ?뺥솗?쒖? ?뺤씤?댁＜?몄슂.");
      }
    }, 15000);

    uploadTask.on('state_changed', 
      (snapshot) => {
        const progress = (snapshot.bytesTransferred / snapshot.totalBytes) * 100;
        setUploadProgress(Math.round(progress));
      }, 
      (error) => {
        clearTimeout(timeoutId);
        console.error("Upload failed", error);
        alert(`?숈쁺???낅줈??以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎: ${error.message}`);
        setIsVideoUploading(false);
      }, 
      () => {
        clearTimeout(timeoutId);
        getDownloadURL(uploadTask.snapshot.ref).then((downloadURL) => {
          setFormData(prev => ({ ...prev, videoUrl: downloadURL }));
          setIsVideoUploading(false);
          alert("?숈쁺?곸씠 ?깃났?곸쑝濡??낅줈?쒕릺?덉뒿?덈떎!");
        }).catch((err: unknown) => {
          console.error("URL retrieval failed", err);
          alert("?숈쁺??寃쎈줈瑜?媛?몄삤?붾뜲 ?ㅽ뙣?덉뒿?덈떎.");
          setIsVideoUploading(false);
        });
      }
    );
  };

  const handleDateChange = (index: number, value: string) => {
    let newDates = [...dates];
    newDates[index] = value;

    // Auto-fill subsequent weeks based on the 1st week
    if (index === 0 && value) {
      const d = new Date(value);
      for (let i = 1; i < 4; i++) {
        const nextDate = new Date(d);
        nextDate.setDate(d.getDate() + i * 7);
        // Format to YYYY-MM-DD for input type="date"
        const offset = nextDate.getTimezoneOffset()
        const kstNextDate = new Date(nextDate.getTime() - (offset*60*1000))
        newDates[i] = kstNextDate.toISOString().split('T')[0];
      }
      // Implicitly set the Day of the Week string
      const days = ['??, '??, '??, '??, '紐?, '湲?, '??];
      setFormData(prev => ({ ...prev, time: `留ㅼ＜ ${days[d.getDay()]}?붿씪 ${startTime} - ${endTime}` }));
    }

    setDates(newDates.slice(0, 4)); // Ensure strictly 4 dates
  };

  const addCurriculumWeek = () => setCurriculumWeeks(prev => [...prev, '']);
  const removeCurriculumWeek = () => setCurriculumWeeks(prev => prev.length > 1 ? prev.slice(0, -1) : prev);

  const handleCurriculumChange = (index: number, value: string) => {
    const newWeeks = [...curriculumWeeks];
    newWeeks[index] = value;
    setCurriculumWeeks(newWeeks);
  }

  const handleSubmit = () => {
    let finalCurriculum = '';
    if (hasCurriculum) {
      finalCurriculum = curriculumWeeks
